<?php $xml = new DOMDocument("1.0", "UTF-8"); $xml->formatOutput = true; $cricket = $xml->createElement("cricket"); $xml->appendChild($cricket); $players = [      ["name" => "Virat Kohli", "runs" => 120, "wickets" => 5],      ["name" => "Rohit Sharma", "runs" => 95, "wickets" => 2],      ["name" => "KL Rahul", "runs" => 150, "wickets" => 1],      ["name" => "Hardik Pandya", "runs" => 80, "wickets" => 10],      ["name" => "Shubman Gill", "runs" => 130, "wickets" => 0] ]; foreach ($players as $p) {     $player = $xml->createElement("player_info");     $name = $xml->createElement("player", $p["name"]);     $runs = $xml->createElement("runs", $p["runs"]);     $wickets = $xml->createElement("wickets", $p["wickets"]);     $player->appendChild($name);     $player->appendChild($runs);     $player->appendChild($wickets);     $cricket->appendChild($player); } $xml->save("cricket.xml"); echo "<h3>Players with more than 100 runs</h3>"; echo "<table border='1' cellpadding='10'>"; echo "<tr><th>Name</th><th>Runs</th><th>Wickets</th></tr>"; $xmlData = simplexml_load_file("cricket.xml"); foreach ($xmlData->player_info as $p) {     if ($p->runs > 100) {     echo "<tr>";     echo "<td>" . $p->player . "</td>";     echo "<td>" . $p->runs . "</td>";     echo "<td>" . $p->wickets . "</td>";     echo "</tr>";     }   } echo "</table>"; ?>
